"""

from beets.autotag import mb
from beets.autotag.hooks import TrackInfo


def test_track_disambig_extraction():
    """Test that track disambiguation is extracted from MusicBrainz recordings."""

    # Create a mock recording with disambiguation
    recording_with_disambig = {
        'title': 'Song Title',
        'id': 'recording-id-123',
        'disambiguation': 'Special Edition',
        'artist-credit': [
            {
                'artist': {
                    'name': 'Artist Name',
                    'id': 'artist-id-123',
                    'sort-name': 'Name, Artist',
                },
                'name': 'Artist Name',
            }
        ],
        'length': '200000',  # 200 seconds in milliseconds
    }

    # Process the recording through track_info
    track_info = mb.track_info(recording_with_disambig)

    print("Track Info attributes:")
    for attr in dir(track_info):
        if not attr.startswith('_'):
            try:
                value = getattr(track_info, attr)
                if not callable(value):
                    print(f"  {attr}: {value}")
            except:
                pass

    # Check if disambiguation field exists
    if hasattr(track_info, 'disambig') or hasattr(track_info, 'trackdisambig'):
        disambig_value = getattr(track_info, 'disambig', getattr(track_info, 'trackdisambig', None))
        print(f"\nTrack disambiguation found: {disambig_value}")
        return True
    else:
        print("\nTrack disambiguation field NOT found!")
        return False


