    # Process the recording through track_info
    track_info = mb.track_info(recording_without_disambig)

    print("\nTrack without disambig - attributes:")
    for attr in dir(track_info):
        if not attr.startswith('_'):
            try:
                value = getattr(track_info, attr)
                if not callable(value):
                    print(f"  {attr}: {value}")
            except:
                pass


