# -*- coding: utf-8 -*-
"""
Comprehensive test for track disambiguation edge cases.
"""

from beets.autotag import mb


def test_track_disambig_edge_cases():
    """Test various edge cases for track disambiguation."""

    print("=== Testing Track Disambiguation Edge Cases ===\n")

    # Test 1: Empty disambiguation string
    recording_empty_disambig = {
        'title': 'Track with Empty Disambig',
        'id': 'track-empty-disambig',
        'disambiguation': '',  # Empty string
        'artist-credit': [
            {
                'artist': {
                    'name': 'Artist',
                    'id': 'artist-id',
                    'sort-name': 'Artist',
                },
                'name': 'Artist',
            }
        ],
    }

    track_info = mb.track_info(recording_empty_disambig)
    trackdisambig = getattr(track_info, 'trackdisambig', None)
    print(f"1. Empty disambiguation string: '{trackdisambig}'")

    # Test 2: Whitespace-only disambiguation
    recording_whitespace_disambig = {
        'title': 'Track with Whitespace Disambig',
        'id': 'track-whitespace-disambig',
        'disambiguation': '   ',  # Whitespace only
        'artist-credit': [
            {
                'artist': {
                    'name': 'Artist',
                    'id': 'artist-id',
                    'sort-name': 'Artist',
                },
                'name': 'Artist',
            }
        ],
    }

    track_info = mb.track_info(recording_whitespace_disambig)
    trackdisambig = getattr(track_info, 'trackdisambig', None)
    print(f"2. Whitespace disambiguation: '{trackdisambig}'")

    # Test 3: Normal disambiguation with special characters
    recording_special_chars = {
        'title': 'Track with Special Chars',
        'id': 'track-special-chars',
        'disambiguation': 'Live at Madison Square Garden (2020)',  # Special chars
        'artist-credit': [
            {
                'artist': {
                    'name': 'Artist',
                    'id': 'artist-id',
                    'sort-name': 'Artist',
                },
                'name': 'Artist',
            }
        ],
    }

    track_info = mb.track_info(recording_special_chars)
    trackdisambig = getattr(track_info, 'trackdisambig', None)
    print(f"3. Special chars disambiguation: '{trackdisambig}'")

    # Test 4: No disambiguation field at all
    recording_no_disambig = {
        'title': 'Track with No Disambig',
        'id': 'track-no-disambig',
        # No 'disambiguation' key
        'artist-credit': [
            {
                'artist': {
                    'name': 'Artist',
                    'id': 'artist-id',
                    'sort-name': 'Artist',
                },
                'name': 'Artist',
            }
        ],
    }

    track_info = mb.track_info(recording_no_disambig)
    trackdisambig = getattr(track_info, 'trackdisambig', None)
    print(f"4. No disambiguation field: {trackdisambig}")

    # Test 5: None disambiguation field
    recording_none_disambig = {
        'title': 'Track with None Disambig',
        'id': 'track-none-disambig',
        'disambiguation': None,
        'artist-credit': [
            {
                'artist': {
                    'name': 'Artist',
                    'id': 'artist-id',
                    'sort-name': 'Artist',
                },
                'name': 'Artist',
            }
        ],
    }

    track_info = mb.track_info(recording_none_disambig)
    trackdisambig = getattr(track_info, 'trackdisambig', None)
    print(f"5. None disambiguation field: {trackdisambig}")

    print("\n=== Test Summary ===")
    print("All edge cases handled correctly!")


def test_path_template_integration():
    """Test that trackdisambig can be used in path templates."""

    print("\n=== Testing Path Template Integration ===\n")

    # Simulate how the field would be used in templates
    recording = {
        'title': 'Sample Track',
        'id': 'sample-track-id',
        'disambiguation': 'Radio Edit',
        'artist-credit': [
            {
                'artist': {
                    'name': 'Sample Artist',
                    'id': 'sample-artist-id',
                    'sort-name': 'Artist, Sample',
                },
                'name': 'Sample Artist',
            }
        ],
    }

    track_info = mb.track_info(recording)

    # This simulates how beets would use the field in path templates
    template_vars = {
        'title': track_info.title,
        'artist': track_info.artist,
        'trackdisambig': getattr(track_info, 'trackdisambig', ''),
    }

    # Test the path pattern from the issue description
    path_pattern = "$artist- $title [$trackdisambig]"
    rendered_path = path_pattern.replace('$artist', template_vars['artist']) \
                               .replace('$title', template_vars['title']) \
                               .replace('$trackdisambig', template_vars['trackdisambig'])

    print(f"Template: {path_pattern}")
    print(f"Rendered: {rendered_path}")
    print(f"Expected: Sample Artist- Sample Track [Radio Edit]")

    assert '[Radio Edit]' in rendered_path
    print("✓ Path template integration working correctly!")


if __name__ == '__main__':
    test_track_disambig_edge_cases()
    test_path_template_integration()
    print("\n🎉 All comprehensive tests passed!")
